130	void find_best_corner(int corner_id, CornerPlan& best) {
131	    best.score = -1;
132	
133	    for (int wr = 2; wr <= 29; wr++) {
134	        for (int wc = 2; wc <= 29; wc++) {
135	            int pets_inside = 0;
136	            int area = 0;
137	            int cost = 0;
138	            int r_min, r_max, c_min, c_max;
139	
140	            if (corner_id == 0) { // Top-Left: sealed region [1..wr-1] x [1..wc-1]
141	                r_min = 1; r_max = wr - 1; c_min = 1; c_max = wc - 1;
142	                cost = wc + (wr - 1); // horizontal wall has wc cells, vertical has wr-1 cells
143	            } else if (corner_id == 1) { // Top-Right: sealed region [1..wr-1] x [wc+1..30]
144	                r_min = 1; r_max = wr - 1; c_min = wc + 1; c_max = GRID_SIZE;
145	                cost = (GRID_SIZE - wc + 1) + (wr - 1);
146	            } else if (corner_id == 2) { // Bottom-Left: sealed region [wr+1..30] x [1..wc-1]
147	                r_min = wr + 1; r_max = GRID_SIZE; c_min = 1; c_max = wc - 1;
148	                cost = wc + (GRID_SIZE - wr);
149	            } else { // Bottom-Right: sealed region [wr+1..30] x [wc+1..30]
150	                r_min = wr + 1; r_max = GRID_SIZE; c_min = wc + 1; c_max = GRID_SIZE;
151	                cost = (GRID_SIZE - wc + 1) + (GRID_SIZE - wr);
152	            }
153	
154	            area = (r_max - r_min + 1) * (c_max - c_min + 1);
155	            if (area < 50) continue; // too small
156	            if (cost > 40) continue; // too expensive
157	
158	            int pets_near = 0; // pets on the wall boundary that could leak
159	            for (auto& p : pets) {
160	                if (p.r >= r_min && p.r <= r_max && p.c >= c_min && p.c <= c_max) {
161	                    pets_inside++;
162	                }
163	                // Count pets that are on the wall line itself (adjacent to safe zone)
164	                bool on_h_wall = false, on_v_wall = false;
165	                if (corner_id == 0 || corner_id == 1) {
166	                    on_h_wall = (p.r == wr && p.c >= c_min && p.c <= c_max);
167	                    on_v_wall = (p.c == wc && p.r >= r_min && p.r <= r_max);
168	                } else {
169	                    on_h_wall = (p.r == wr && p.c >= c_min && p.c <= c_max);
170	                    on_v_wall = (p.c == wc && p.r >= r_min && p.r <= r_max);
171	                }
172	                if (on_h_wall || on_v_wall) pets_near++;
173	            }
174	
175	            double base_score = (double)area / 900.0 * std::pow(2.0, -(double)pets_inside);
176	
177	            // Penalize by construction cost
178	            double time_factor = 1.0 / (1.0 + cost * 0.01);
179	
180	            // Reward 0 pets inside; penalize pets more for leakage risk
181	            double pet_bonus = (pets_inside == 0) ? 2.0 : std::pow(0.7, pets_inside);
182	            // Penalize pets near the wall boundary (leakage risk during construction)
183	            double near_penalty = 1.0 / (1.0 + pets_near * 0.1);
184	
185	            // Penalize by average human distance to the wall region
186	            double avg_human_dist = 0;
187	            for (int hi = 0; hi < M; hi++) {
188	                int dr = 0, dc = 0;
189	                if (humans[hi].r < r_min) dr = r_min - humans[hi].r;
190	                else if (humans[hi].r > r_max) dr = humans[hi].r - r_max;
191	                if (humans[hi].c < c_min) dc = c_min - humans[hi].c;
192	                else if (humans[hi].c > c_max) dc = humans[hi].c - c_max;
193	                avg_human_dist += dr + dc;
194	            }
195	            avg_human_dist /= M;
196	            double dist_factor = 1.0 / (1.0 + avg_human_dist * 0.02);
197	
198	            double score = base_score * time_factor * pet_bonus * dist_factor * near_penalty;
199	
200	            if (score > best.score) {
201	                best.corner = corner_id;
202	                best.wall_row = wr;
203	                best.wall_col = wc;
204	                best.area = area;
205	                best.cost = cost;
206	                best.pets_inside = pets_inside;
207	                best.score = score;
208	                best.r_min = r_min;
209	                best.r_max = r_max;
210	                best.c_min = c_min;
211	                best.c_max = c_max;
212	            }
213	        }
214	    }
215	}
