379	int main() {
380	    std::ios_base::sync_with_stdio(false);
381	    std::cin.tie(NULL);
382	
383	    std::cin >> N;
384	    pets.resize(N);
385	    pet_types.resize(N);
386	    for (int i = 0; i < N; i++) {
387	        std::cin >> pets[i].r >> pets[i].c >> pet_types[i];
388	    }
389	
390	    std::cin >> M;
391	    humans.resize(M);
392	    for (int i = 0; i < M; i++) {
393	        std::cin >> humans[i].r >> humans[i].c;
394	    }
395	
396	    memset(grid, false, sizeof(grid));
397	    choose_strategy();
398	
399	    if (strategy_mode == 0) {
400	        // L-shape mode
401	        for (int p = 0; p < num_plans; p++) {
402	            plan_walls[p] = get_wall_cells(plans[p]);
403	        }
404	        assign_humans_lshape();
405	    } else {
406	        // Dual horizontal wall mode
407	        assign_humans_dual_h();
408	    }
409	
410	    for (int turn = 0; turn < NUM_TURNS; turn++) {
411	        std::string actions(M, '.');
412	        std::vector<Point> walls_being_built;
413	
414	        if (strategy_mode == 0) {
415	            // L-shape strategy
416	            for (int i = 0; i < M; i++) {
417	                int my_plan = human_plan_assignment[i];
418	                auto& my_walls = plan_walls[my_plan];
419	                auto& plan = plans[my_plan];
420	
421	                // Find best unbuilt wall cell: balance proximity to human and priority from corner outward
422	                int best_idx = -1;
423	                int best_priority = INF;
424	
425	                // The intersection point of the L-shape
426	                int corner_r = plan.wall_row;
427	                int corner_c = plan.wall_col;
428	
429	                for (int w = 0; w < (int)my_walls.size(); w++) {
430	                    Point wc = my_walls[w];
431	                    if (grid[wc.r][wc.c]) continue;
432	
433	                    // Check not already claimed this turn
434	                    bool claimed = false;
435	                    for (auto& wb : walls_being_built) {
436	                        if (wb == wc) { claimed = true; break; }
437	                    }
438	                    if (claimed) continue;
439	
440	                    int dist = std::abs(humans[i].r - wc.r) + std::abs(humans[i].c - wc.c);
441	                    // Distance from corner intersection (build from corner outward)
442	                    int corner_dist = std::abs(wc.r - corner_r) + std::abs(wc.c - corner_c);
443	                    // Combined priority: mostly distance but with a small bias toward corner
444	                    int priority = dist * 2 + corner_dist;
445	                    if (priority < best_priority) {
446	                        best_priority = priority;
447	                        best_idx = w;
448	                    }
449	                }
450	
451	                if (best_idx == -1) {
452	                    // All walls built - move to center of safe zone
453	                    int tr = (plan.r_min + plan.r_max) / 2;
454	                    int tc = (plan.c_min + plan.c_max) / 2;
455	                    Point target = {tr, tc};
456	                    if (!passable(target.r, target.c)) {
457	                        // Find any passable cell in safe zone
458	                        bool found = false;
459	                        for (int r = plan.r_min; r <= plan.r_max && !found; r++) {
460	                            for (int c = plan.c_min; c <= plan.c_max && !found; c++) {
461	                                if (passable(r, c)) {
462	                                    target = {r, c};
463	                                    found = true;
464	                                }
465	                            }
466	                        }
467	                    }
468	                    if (humans[i] != target) {
469	                        actions[i] = move_toward(humans[i], target);
470	                    }
471	                } else {
472	                    Point wall_target = my_walls[best_idx];
473	
474	                    // Find a position adjacent to wall_target from the SAFE side
475	                    Point stand_pos = {-1, -1};
476	                    int best_stand_dist = INF;
477	
478	                    for (int d = 0; d < 4; d++) {
479	                        int sr = wall_target.r + DR[d];
480	                        int sc = wall_target.c + DC[d];
481	                        if (!passable(sr, sc)) continue;
482	
483	                        // Prefer standing inside the safe zone
484	                        bool in_safe = is_safe_side(plan, sr, sc);
485	
486	                        int dist = std::abs(humans[i].r - sr) + std::abs(humans[i].c - sc);
487	                        // Give big bonus to safe-side positions
488	                        int effective_dist = in_safe ? dist : dist + 100;
489	
490	                        if (effective_dist < best_stand_dist) {
491	                            best_stand_dist = effective_dist;
492	                            stand_pos = {sr, sc};
493	                        }
494	                    }
495	
496	                    if (stand_pos.r == -1) {
497	                        // Can't find standing position, try any adjacent
498	                        for (int d = 0; d < 4; d++) {
499	                            int sr = wall_target.r + DR[d];
500	                            int sc = wall_target.c + DC[d];
501	                            if (passable(sr, sc)) {
502	                                stand_pos = {sr, sc};
503	                                break;
504	                            }
505	                        }
506	                    }
507	
508	                    if (stand_pos.r == -1) {
509	                        actions[i] = '.';
510	                    } else if (humans[i] == stand_pos) {
511	                        // Build the wall
512	                        if (can_build_wall(wall_target.r, wall_target.c)) {
513	                            for (int d = 0; d < 4; d++) {
514	                                if (humans[i].r + DR[d] == wall_target.r &&
515	                                    humans[i].c + DC[d] == wall_target.c) {
516	                                    actions[i] = BUILD_CH[d];
